class Solution:
    def stoneGameIII(self, stoneValue):
        n = len(stoneValue)
        # suffix sums for fast range sums
        suffix = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            suffix[i] = suffix[i+1] + stoneValue[i]
        dp = [0] * (n + 1)  # dp[i] = best advantage from index i
        for i in range(n - 1, -1, -1):
            best = float('-inf')
            take = 0
            for k in range(1, 4):
                if i + k - 1 < n:
                    take += stoneValue[i + k - 1]
                    best = max(best, take - dp[i + k])
            dp[i] = best
        if dp[0] > 0:
            return 'Alice'
        elif dp[0] < 0:
            return 'Bob'
        return 'Tie'

